// ── ABM Servicios/Precios en D1 (reemplaza la gsheet) ──
let _svCache = null;

// [COMPARTIDA] usada por ctCargarServicios y abrirSelectorServicios
async function svFetchServicios(force) {
  if (_svCache && !force) return _svCache;
  const r = await fetch(CLIENTES_WORKER + '/servicios', { headers: { 'Authorization': 'Bearer ' + getAdminJWT() } });
  if (!r.ok) throw new Error('Error cargando servicios (' + r.status + ')');
  _svCache = await r.json();
  return _svCache;
}

function svToggle() {
  const body = document.getElementById('sv-body');
  const arrow = document.getElementById('sv-arrow');
  const open = body.style.display !== 'none';
  body.style.display = open ? 'none' : 'block';
  arrow.textContent = open ? '▼' : '▲';
  if (!open) svRender();
}

async function svRender() {
  const el = document.getElementById('sv-list');
  el.innerHTML = '<div style="color:var(--gray);font-size:12px;padding:8px 0">Cargando...</div>';
  try {
    const list = await svFetchServicios(true);
    if (!list.length) { el.innerHTML = '<div style="color:var(--gray);font-size:12px;padding:8px 0">Sin servicios cargados. Agregá el primero abajo.</div>'; return; }
    el.innerHTML = list.map(s => `
      <div style="display:flex;align-items:center;gap:8px;padding:7px 0;border-bottom:1px solid rgba(255,255,255,0.06)">
        <span style="font-size:11px;color:var(--gray2);width:34px;flex-shrink:0">${s.id}</span>
        <input class="form-input" style="flex:1;padding:6px 10px;font-size:12px" value="${(s.descripcion||'').replace(/"/g,'&quot;')}" onchange="svUpdate('${s.id}','descripcion',this.value)">
        <input class="form-input" type="number" style="width:120px;padding:6px 10px;font-size:12px" value="${s.pesos||0}" onchange="svUpdate('${s.id}','pesos',this.value)">
        <button class="btn-sm" onclick="svToggleActivo('${s.id}')" title="Activar / desactivar" style="opacity:${s.activo?1:0.35}">${s.activo?'ON':'OFF'}</button>
        <button class="btn-sm" onclick="svDelete('${s.id}')" style="color:var(--red)">✕</button>
      </div>`).join('');
  } catch(err) { el.innerHTML = '<div style="color:var(--red);font-size:12px;padding:8px 0">' + err.message + '</div>'; }
}

async function svPost(body) {
  const r = await fetch(CLIENTES_WORKER + '/servicios', { method: 'POST', headers: { 'Authorization': 'Bearer ' + getAdminJWT(), 'Content-Type': 'application/json' }, body: JSON.stringify(body) });
  if (!r.ok) { toast('Error guardando servicio', 'error'); return null; }
  _svCache = null;
  _cachedServicios = null;
  return r.json();
}

async function svAdd() {
  const desc = document.getElementById('sv-new-desc').value.trim();
  if (!desc) { toast('Descripción requerida', 'error'); return; }
  const res = await svPost({
    id: document.getElementById('sv-new-id').value.trim(),
    descripcion: desc,
    pesos: Number(document.getElementById('sv-new-pesos').value) || 0
  });
  if (res && res.ok) {
    ['sv-new-id','sv-new-desc','sv-new-pesos'].forEach(id => document.getElementById(id).value = '');
    toast('Servicio agregado ✓');
    svRender();
    ctCargarServicios();
  }
}

async function svUpdate(id, field, value) {
  const s = (_svCache || await svFetchServicios()).find(x => x.id === id);
  if (!s) return;
  const res = await svPost({ ...s, [field]: field === 'pesos' ? (Number(value) || 0) : value });
  if (res && res.ok) { toast('Guardado ✓'); ctCargarServicios(); }
}

async function svToggleActivo(id) {
  const s = (_svCache || await svFetchServicios()).find(x => x.id === id);
  if (!s) return;
  const res = await svPost({ ...s, activo: s.activo ? 0 : 1 });
  if (res && res.ok) { svRender(); ctCargarServicios(); }
}

async function svDelete(id) {
  if (!confirm('¿Eliminar el servicio ' + id + '?')) return;
  const r = await fetch(CLIENTES_WORKER + '/servicios/' + id, { method: 'DELETE', headers: { 'Authorization': 'Bearer ' + getAdminJWT() } });
  if (r.ok) { _svCache = null; _cachedServicios = null; toast('Servicio eliminado'); svRender(); ctCargarServicios(); }
}

function ctCargarServicios() {
  const grid = document.getElementById('ct-svc-grid');
  if (!grid) return null;
  grid.innerHTML = '<div style="color:var(--gray);font-size:12px;grid-column:1/-1">Cargando...</div>';
  ctSvcReady = svFetchServicios(true)
    .then(data => ctRenderServicios((data || []).filter(s => s.activo !== 0)))
    .catch(err => {
      console.error('[ctCargarServicios]', err);
      grid.innerHTML = `<div style="color:var(--red);font-size:12px;grid-column:1/-1">Error cargando servicios: ${err.message || err}. Cargalos en "Servicios y precios".</div>`;
    });
  return ctSvcReady;
}

