async function genInviteUrl(inv) {
  const nombre = toSlug(inv.config.novios || inv.config.titulo || 'invitacion');
  const fechaRaw = inv.config.fecha_display || inv.config.fecha_iso || '';
  const fecha = toSlug(fechaRaw);
  const suffix = String(inv.id).slice(-4);
  const slug = nombre + (fecha ? '-' + fecha : '') + '-' + suffix;
  const base = getInvBaseUrl();
  try {
    const res = await fetch(CONFIG.CF_URL + '/invite/' + slug, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': CONFIG.CF_AUTH },
      body: JSON.stringify(inv.config)
    });
    if (res.ok) return base + '?i=' + slug;
  } catch(e) {}
  const encoded = encodeURIComponent(btoa(unescape(encodeURIComponent(JSON.stringify(inv.config)))));
  return base + '?c=' + encoded;
}

