function toggleTriviaEditor() {
  const ed = document.getElementById('trivia-editor');
  const ic = document.getElementById('trivia-toggle-icon');
  if(!ed) return;
  const open = ed.style.display !== 'none';
  ed.style.display = open ? 'none' : '';
  ic.textContent = open ? '▼ expandir' : '▲ contraer';
  if(!open) renderTriviaLista();
