function escHtml(s) { return String(s||'').replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;'); }
function renderTriviaLista() {
  const wrap = document.getElementById('trivia-lista');
  if(!wrap) return;
  if(!_invTrivia.length) _invTrivia = TRIVIA_DEFAULT.map(p => ({...p,opciones:[...p.opciones]}));
  wrap.innerHTML = _invTrivia.map((p,i) => `
    <div style="background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.08);padding:12px;margin-bottom:8px;border-radius:2px">
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px">
        <label style="display:flex;align-items:center;gap:6px;font-size:11px;cursor:pointer;flex:1">
          <input type="checkbox" ${p.activa?'checked':''} onchange="triviaToggle(${i},this.checked)" style="accent-color:var(--gold)">
          <span style="color:${p.activa?'var(--white)':'var(--gray)'}">Activa</span>
        </label>
        <button onclick="triviaSubir(${i})" style="background:none;border:none;color:var(--gray);cursor:pointer;font-size:12px;padding:2px 6px">↑</button>
        <button onclick="triviaBajar(${i})" style="background:none;border:none;color:var(--gray);cursor:pointer;font-size:12px;padding:2px 6px">↓</button>
        <button onclick="triviaEliminar(${i})" style="background:none;border:none;color:#e55;cursor:pointer;font-size:11px;padding:2px 6px">✕</button>
      </div>
      <input class="form-input" value="${escHtml(p.pregunta)}" oninput="_invTrivia[${i}].pregunta=this.value" placeholder="Pregunta..." style="margin-bottom:6px;font-size:12px">
      ${p.opciones.map((op,j)=>`
        <div style="display:flex;align-items:center;gap:6px;margin-bottom:4px">
          <input type="radio" name="trivia-correcta-${i}" ${p.correcta===j?'checked':''} onchange="triviaSetCorrecta(${i},${j})" style="accent-color:var(--gold);flex-shrink:0">
          <input class="form-input" value="${escHtml(op)}" oninput="_invTrivia[${i}].opciones[${j}]=this.value" placeholder="Opción ${j+1}" style="font-size:12px">
        </div>`).join('')}
      <small style="color:var(--gray);font-size:9px;letter-spacing:1px">El radio marcado es la respuesta correcta</small>
    </div>`).join('');
}
function triviaToggle(i,v) { _invTrivia[i].activa=v; renderTriviaLista(); }
function triviaSetCorrecta(i,j) { _invTrivia[i].correcta=j; }
function triviaSubir(i) { if(i===0)return; [_invTrivia[i-1],_invTrivia[i]]=[_invTrivia[i],_invTrivia[i-1]]; renderTriviaLista(); }
function triviaBajar(i) { if(i>=_invTrivia.length-1)return; [_invTrivia[i],_invTrivia[i+1]]=[_invTrivia[i+1],_invTrivia[i]]; renderTriviaLista(); }
function triviaEliminar(i) { if(!confirm('¿Eliminar esta pregunta?'))return; _invTrivia.splice(i,1); renderTriviaLista(); }
function triviaAgregar() {
  if(!_invTrivia.length) _invTrivia = TRIVIA_DEFAULT.map(p=>({...p,opciones:[...p.opciones]}));
  _invTrivia.push({id:Date.now(),activa:true,pregunta:'',opciones:['','',''],correcta:0});
  const ed = document.getElementById('trivia-editor');
  if(ed) ed.style.display='';
  renderTriviaLista();
}

